/**
 * Maps Zod types to their FlatBuffers schema counterparts.
 * @param type A Zod type object from the schema.
 * @returns The FlatBuffers type as a string.
 */
function zodToFbsType(type) {
    const typeName = type._def.typeName;
    switch (typeName) {
        case "ZodString":
            return "string";
        case "ZodNumber":
            return "double"; // Using double for general-purpose numbers
        case "ZodBoolean":
            return "bool";
        // TODO: Add support for more Zod types like arrays, dates, etc.
        default:
            throw new Error(`Unsupported Zod type for FBS generation: ${typeName}`);
    }
}
/**
 * Generates the full FlatBuffers schema (.fbs) file content as a string.
 * @param schema The processed schema object.
 * @returns The .fbs schema as a string.
 */
export function generateFbs(schema) {
    const { nodes } = schema;
    const fbsTables = [];
    // Generate a table for each node type
    for (const nodeName in nodes) {
        const zodSchema = nodes[nodeName];
        const fields = Object.entries(zodSchema.shape)
            .map(([fieldName, zodType]) => {
            return `  ${fieldName}:${zodToFbsType(zodType)};`;
        })
            .join("\n");
        const table = `table ${capitalize(nodeName)} {\n${fields}\n}`;
        fbsTables.push(table);
    }
    // Generate a table for storing relationship indices
    const idVectorTable = `
table IdVector {
  ids:[string];
}`;
    fbsTables.push(idVectorTable);
    // The root type could be used for schema evolution later if needed
    const rootType = `root_type ${capitalize(Object.keys(nodes)[0])};`;
    return `// Generated by @zgdb/cli\n\n${fbsTables.join("\n\n")}\n\n${rootType}\n`;
}
function capitalize(s) {
    return s.charAt(0).toUpperCase() + s.slice(1);
}
